<style lang="scss" scoped>
.sp-form {
  margin-top: 24px;
}
.sp-finder {
  margin-top: 8px;
}
</style>
<template>
  <el-tabs type="card">
    <el-tab-pane label="社區團配置">
      <SpForm
        v-model="form"
        :form-list="formList"
        @onSubmit="onSaveConfig"
      />
    </el-tab-pane>
    <el-tab-pane label="團長註冊項配置">
      <SpFinder
        ref="finder"
        no-selection
        :setting="setting"
        url="/community/chief/apply_fields"
      />

      <!-- 團長註冊配置 -->
      <SpDialog
        ref="registerDialogRef"
        v-model="registerDialog"
        :title="`${registerForm.id ? '編輯配置' : '新增配置'}`"
        :form="registerForm"
        :form-list="registerFormList"
        @onSubmit="onResisterSubmit"
      />
    </el-tab-pane>
  </el-tabs>
</template>

<script>
import { mapGetters } from 'vuex'
import { createSetting } from '@shopex/finder'
import copyLink from './comps/copyLink.vue'
export default {
  components: {},
  data () {
    return {
      form: {
        condition_type: 'num',
        condition_money: '',
        chief_desc: '',
        rebate_ratio: 0,
        distance_limit: 0,
        aggrement: '',
        explanation: ''
      },
      formList: [
        {
          label: '成團條件',
          key: 'condition_type',
          type: 'radio',
          options: [
            { label: 'num', name: '按商品數量' },
            { label: 'money', name: '按成團金額' }
          ],
          tip: '說明：按活動商品設置的起訂量成團，0為不限制',
          onChange: (e) => {
            if (e == 'num') {
              this.formList[0].tip = '說明：按活動商品設置的起訂量成團，0為不限制'
              this.formList[1].isShow = false
            } else {
              this.formList[0].tip = '說明：整團成團最低金額，0為不限制'
              this.formList[1].isShow = true
            }
          }
        },
        {
          label: '最低成團金額(元)',
          key: 'condition_money',
          type: 'input',
          placeholder: '請輸入成團金額',
          required: true,
          message: '不能為空',
          isShow: false
        },
        {
          label: '團長邀請地址',
          key: 'invitation_code',
          component: () => <copyLink info={this.regimentalCommanderAddress} />
        },
        {
          label: '團長申請頁',
          key: 'chief_desc',
          type: 'text'
        },
        {
          label: '傭金設置',
          key: 'rebate_ratio',
          type: 'input',
          append: '%',
          placeholder: '傭金比列',
          tip: '團長根據成團金額按百分比例獲取傭金，設置為0時則不計算傭金'
        },
        {
          label: '成團距離',
          key: 'distance_limit',
          type: 'input',
          append: '公里',
          placeholder: '成團距離'
        },
        {
          label: '團長註冊協議',
          key: 'aggrement',
          type: 'richText',
          required: true,
          message: '不能為空'
        },
        {
          label: '申請頁說明',
          key: 'explanation',
          type: 'richText',
          required: true,
          message: '不能為空'
        }
      ],
      tableData: [],
      setting: createSetting({
        actions: [
          {
            name: '新增配置',
            key: 'detail',
            type: 'button',
            slot: 'header',
            buttonType: 'primary is-plain',
            action: {
              handler: async (val) => {
                this.registerForm.id = ''
                this.$refs.registerDialogRef.resetForm()
                this.registerDialog = true
              }
            }
          },
          {
            name: '編輯',
            key: 'detail',
            type: 'button',
            buttonType: 'text',
            action: {
              handler: async ([row]) => {
                this.registerForm.id = row.id
                this.registerForm.label = row.label
                this.registerForm.field_type = row.field_type
                this.registerForm.alert_required_message = row.alert_required_message
                this.registerDialog = true
              }
            }
          },
          {
            name: '刪除',
            key: 'detail',
            type: 'button',
            buttonType: 'text',
            action: {
              handler: async ([row]) => {
                await this.$confirm('是否刪除', '提示')
                await this.$api.community.deleteCommunityField(row.id)
                this.$refs.finder.refresh()
              }
            }
          }
        ],
        columns: [
          { name: '訊息', key: 'label' },
          {
            name: '是否啟用',
            key: 'is_open',
            render: (h, { row }) =>
              h('el-switch', {
                props: {
                  'value': row.is_open,
                  'active-value': 1,
                  'inactive-value': 0
                },
                on: {
                  change: async (e) => {
                    await this.$api.community.modifyFieldSwitch(row.id, {
                      type: 1,
                      switch: e
                    })
                    row.is_open = e
                  }
                }
              })
          },
          {
            name: '必填',
            key: 'is_required',
            render: (h, { row }) =>
              h('el-switch', {
                props: {
                  'value': row.is_required,
                  'active-value': 1,
                  'inactive-value': 0
                },
                on: {
                  change: async (e) => {
                    await this.$api.community.modifyFieldSwitch(row.id, {
                      type: 2,
                      switch: e
                    })
                    row.is_required = e
                  }
                }
              })
          },
          {
            name: '可修改',
            key: 'is_edit',
            render: (h, { row }) =>
              h('el-switch', {
                props: {
                  'value': row.is_edit,
                  'active-value': 1,
                  'inactive-value': 0
                },
                on: {
                  change: async (e) => {
                    await this.$api.community.modifyFieldSwitch(row.id, {
                      type: 3,
                      switch: e
                    })
                    row.is_edit = e
                  }
                }
              })
          },
          { name: '訊息格式', key: 'field_type_desc' },
          { name: '提示文案', key: 'alert_required_message' }
        ]
      }),
      registerDialog: false,
      registerForm: {
        id: '',
        label: '',
        field_type: 1,
        alert_required_message: ''
      },
      registerFormList: [
        {
          label: '配置標題:',
          key: 'label',
          type: 'input',
          placeholder: '請輸入標題',
          required: true,
          message: '不能為空'
        },
        {
          label: '訊息格式:',
          key: 'field_type',
          placeholder: '請選擇訊息格式',
          type: 'select',
          options: [
            { title: '文本', value: 1 },
            // { title: '數字', value: 2 },
            { title: '日期', value: 3 },
            // { title: '單選項', value: 4 },
            // { title: '複選框', value: 5 },
            { title: '手機號碼', value: 6 },
            { title: '圖片', value: 7 }
          ],
          required: true,
          message: '不能為空',
          onChange: (e) => {
            if (e == 12) {
              this.cancelOrderFormList[1].isShow = true
            } else {
              this.cancelOrderFormList[1].isShow = false
            }
          }
        },
        {
          label: '提示文案:',
          key: 'alert_required_message',
          type: 'input',
          placeholder: '請輸入提示文案',
          required: true,
          message: '不能為空'
        }
      ],
      regimentalCommanderAddress: '',
      wxCode: ''
    }
  },
  computed: {
    ...mapGetters(['shopId'])
  },
  created () {},
  mounted () {
    this.getActivitySetting()
    // this.getCommunityChiefApplyFields()
    // this.getChiefWxCode()
  },
  methods: {
    async onSaveConfig () {
      const { condition_type, condition_money, rebate_ratio, aggrement, explanation, distance_limit } = this.form
      await this.$api.community.modifyActivitySetting({
        condition_type,
        condition_money,
        distance_limit,
        rebate_ratio,
        aggrement,
        explanation
      })
      this.$message.success('修改成功')
    },
    async getActivitySetting () {
      const { condition_money, condition_type, aggrement, explanation, rebate_ratio, regimental_commander_address, distance_limit } =
        await this.$api.community.getActivitySetting()
      this.form = {
        condition_type,
        condition_money,
        chief_desc:
          '您可在模組編輯-熱區圖組件-設置路徑，選擇團長申請頁面路徑供用戶在店鋪首頁進入團長申請頁面',
        rebate_ratio,
        distance_limit,
        aggrement,
        explanation
      }
      // let url = regimental_commander_address
      // if (this.shopId) {
      //   url += `?distributor_id=${this.shopId}`
      // }
      this.regimentalCommanderAddress = regimental_commander_address

      if (condition_type == 'money') {
        this.formList[0].tip = '說明：整團成團最低金額，0為不限制'
        this.formList[1].isShow = true
      }
    },
    async getCommunityChiefApplyFields () {
      const res = await this.$api.community.getActivitySetting()
    },
    async onResisterSubmit () {
      const params = {
        ...this.registerForm
      }
      if (this.registerForm.id) {
        await this.$api.community.modifyCommunityField(params)
      } else {
        await this.$api.community.createCommunityChiefApplyFields(params)
      }
      this.registerDialog = false
      this.$refs.finder.refresh()
    },
    async getChiefWxCode () {
      const params = {
        // wxaAppId: 'wx3e1c17c88abf3e45',
        distributor_id: this.shopId,
        path: 'subpages/community/apply-chief'
      }
      const { base64Image } = await this.$api.community.getChiefWxCode(params)
      this.wxCode = base64Image
    }
  }
}
</script>
